import AbstractView from '../framework/view/abstract-view.js';

import { DateFormat } from '../const.js';
import { getFormettedDate, getDurationTime } from './../utils.js';

function createEventPoint({event, offersModel, destinationsModel}) {
  const eventType = event.type;

  const selectedOffers = event.offers;
  const allOffers = offersModel.getOfferByType(event?.type);

  const eventSity = destinationsModel.getDestinationById(event?.destination)?.name || '';

  const eventDateFrom = getFormettedDate(event.dateFrom, DateFormat.eventDate);
  const eventStartDate = getFormettedDate(event.dateFrom, DateFormat.eventTime);
  const eventEndDate = getFormettedDate(event.dateTo, DateFormat.eventTime);
  const eventTimeSpent = getDurationTime(event.dateFrom, event.dateTo);

  return (`
          <li class="trip-events__item">
              <div class="event">
                <time class="event__date" datetime="${event.dateFrom}">${eventDateFrom}</time>
                <div class="event__type">
                  <img class="event__type-icon" width="42" height="42" src="img/icons/${eventType}.png" alt="Event type icon">
                </div>
                <h3 class="event__title">${eventType} ${eventSity}</h3>
                <div class="event__schedule">
                  <p class="event__time">
                    <time class="event__start-time" datetime="${event.dateFrom}">${eventStartDate}</time>
                    &mdash;
                    <time class="event__end-time" datetime="${event.dateTo}">${eventEndDate}</time>
                  </p>
                  <p class="event__duration">${eventTimeSpent}</p>
                </div>
                <p class="event__price">
                  &euro;&nbsp;<span class="event__price-value">${event.basePrice}</span>
                </p>
                <h4 class="visually-hidden">Offers:</h4>
                <ul class="event__selected-offers">
                ${allOffers.map((offer) => selectedOffers.includes(offer.id) ? `
                  <li class="event__offer">
                    <span class="event__offer-title">${offer.title}</span>&plus;&euro;&nbsp;
                    <span class="event__offer-price">${offer.price}</span>
                  </li>` : '').join('')}
                </ul>
                <button class="event__favorite-btn ${event.isFavorite ? 'event__favorite-btn--active' : ''}" type="button">
                  <span class="visually-hidden">Add to favorite</span>
                  <svg class="event__favorite-icon" width="28" height="28" viewBox="0 0 28 28">
                    <path d="M14 21l-8.22899 4.3262 1.57159-9.1631L.685209 9.67376 9.8855 8.33688 14 0l4.1145 8.33688 9.2003 1.33688-6.6574 6.48934 1.5716 9.1631L14 21z"/>
                  </svg>
                </button>
                <button class="event__rollup-btn" type="button">
                  <span class="visually-hidden">Open event</span>
                </button>
              </div>
            </li>
        `);
}

export default class EventPointView extends AbstractView {
  #event = null;
  #offersModel = null;
  #destination = null;

  constructor({
    event,
    offersModel,
    destinationsModel,
    onSwitchToForm,
    onFavoriteClick,
  }) {
    super();
    this.#event = event;
    this.#offersModel = offersModel;
    this.#destination = destinationsModel;

    this.onSwitchToForm = onSwitchToForm;
    this.onFavoriteClick = onFavoriteClick;
    this.element.querySelector('.event__rollup-btn').addEventListener('click', this.onSwitchToForm);
    this.element.querySelector('.event__favorite-btn').addEventListener('click', this.onFavoriteClick);
  }

  get template() {
    return createEventPoint({
      event: this.#event,
      offersModel: this.#offersModel,
      destinationsModel: this.#destination,
    });
  }
}
